from pyspider.libs.base_handler import *


class Handler(BaseHandler):
    
    @every(minutes=1)
    def on_start(self):
        self.rule = api.get_rule() # first get
        self.crawl('data:, on_test', callback=self.index_page)

    @config(age=30)
    def index_page(self, response):
        self.rule = api.get_rule() # update
        # use rule
        index_use_rule(self.rule)
        
    @config(age=10)
    def other_page(self, response):
        # use rule
        other_use_rule(self.rule)
```
