```python
import functools
import warnings

def deprecated_async(func):
    @functools.wraps(func)
    def inner(*args, **kwargs):
        if 'async' in kwargs:
            if 'async_' in kwargs:
                raise ValueError('cannot use both async and async_ kayword '
                                 'arguments! the latter obsoletes the first.')
            warnings.warn('async keyword argumnt is deprecated, use async_ '
                          'instead', DeprecationWarning)
            kwargs['async_'] = kwargs['async']
            del kwargs['async']
        return func(*args, **kwargs)
    return inner


@deprecated_async
def foo(a, b, async_):
    return(a, b, async_)

print(foo(1, 2, async_=True))
print(foo(1, 2, async=True))
```

