```python
def send_invitation():
  model = current_app.factory('Invitation')
  try:
    invitation = model.get_by_field("email.raw", request.args.get('email')).next()
  except StopIteration:
    flash(_("This invitation is not valid"), "danger")
    return redirect(url_for('.users'))
  
  title = _("[T:F] Invitation link")
  data = {'template': 'notifications/invitation.txt',
          'url': url_for('.signUp', code=invitation.code, _external = True)}
  recipients = [invitation.email]
  send_mail(title, data, recipients)

  invitation.sender = g.user.email
  invitation.sended = datetime.now()
  invitation.updateRole(invitation._id, 'send')
  flash(_("The invitation has been send!"), "success")
  return redirect(request.referrer)
```

