I encountered the same issue. As said before, the 3ds importer generated smooth normals for meshes without smoothing groups. This created some shading artifacts. The attached patch changes the code to only generate smooth normals for faces with smoothing groups assigned. We are currently testing if this is acceptable for our models.

If smooth normals for the whole model are desired, using `aiProcess_GenSmoothNormals` in post-processing yields better/controllable results (by setting `AI_CONFIG_PP_GSN_MAX_SMOOTHING_ANGLE`).

If preferred I can open a pull request with the patch.

```
diff --git a/code/SGSpatialSort.cpp b/code/SGSpatialSort.cpp
index 7a80381e..1b481511 100644
--- a/code/SGSpatialSort.cpp
+++ b/code/SGSpatialSort.cpp
@@ -140,27 +140,20 @@ void SGSpatialSort::FindPositions( const aiVector3D& pPosition,
     }
     else
     {
-        // if the given smoothing group is 0, we'll return all surrounding vertices
-        if (!pSG)
+        // Only return vertices if they have a smoothing group
+        if (pSG)
         {
-            while( it->mDistance < maxDist)
+            while (it->mDistance < maxDist)
             {
-                if((it->mPosition - pPosition).SquareLength() < squareEpsilon)
-                    poResults.push_back( it->mIndex);
+                if ((it->mPosition - pPosition).SquareLength() < squareEpsilon &&
+                    (it->mSmoothGroups & pSG || !it->mSmoothGroups))
+                {
+                    poResults.push_back(it->mIndex);
+                }
                 ++it;
-                if( end == it)break;
+                if (end == it)break;
             }
         }
-        else while( it->mDistance < maxDist)
-        {
-            if((it->mPosition - pPosition).SquareLength() < squareEpsilon &&
-                (it->mSmoothGroups & pSG || !it->mSmoothGroups))
-            {
-                poResults.push_back( it->mIndex);
-            }
-            ++it;
-            if( end == it)break;
-        }
     }
 }
```

