```cpp
enum class log_level {
    debug = 1,
    warn = 2,
    error = 3
};

class plugin_handler {
public:
    void log(log_level lvl, const std::string &msg)
    {
        // ...
    }
};

namespace detail {

struct log_wrapper {
public:
    explicit log_wrapper(plugin_handler* instance)
        : ph_(instance)
    {
        assert(ph_ != nullptr);
    }

    void debug(const std::string &msg)
    {
        ph_->log(log_level::debug, msg);
    }
    void warn(const std::string &msg)
    {
        ph_->log(log_level::warn, msg);
    }
    void error(const std::string &msg)
    {
        ph_->log(log_level::err, msg);
    }

private:
    core::plugin_handler* ph_;
};

}

PYBIND11_MODULE(pybindings, m)
{
    py::class_<detail::log_wrapper>(m, "log")
        .def("debug", &detail::log_wrapper::debug)
        .def("warn", &detail::log_wrapper::warn)
        .def("error", &detail::log_wrapper::error);

    py::class_<plugin_handler>(m, "plugin_handler")
        .def("log", &plugin_handler::log)
        .def("__getattr__", [&](plugin_handler &ph, const std::string &key) {
            if (key == "log")
                return detail::log_wrapper(&ph);

            // Is there some exception that pybind11 translates to AttributeError?
            throw std::invalid_argument(std::string("AttributeError: no plugin handler attribute with key '") + key + "'");
        });
}
```
